_lc{{_id}}_wih = np.random.randn(_lc{{_id}}_hd, _lc{{_id}}_id).astype(np.float32) * {{init_std}}
_lc{{_id}}_whh = np.random.randn(_lc{{_id}}_hd, _lc{{_id}}_hd).astype(np.float32) * {{init_std}}
_lc{{_id}}_b = np.zeros(_lc{{_id}}_hd, dtype=np.float32)
# Time-constant network (input-dependent tau)
_lc{{_id}}_w_tau = np.random.randn(_lc{{_id}}_hd, _lc{{_id}}_id + _lc{{_id}}_hd).astype(np.float32) * {{init_std}}
_lc{{_id}}_b_tau = np.ones(_lc{{_id}}_hd, dtype=np.float32)  # init tau ~ 1.0
# Backbone: sensitivity network
_lc{{_id}}_w_A = np.random.randn(_lc{{_id}}_hd, _lc{{_id}}_hd).astype(np.float32) * {{init_std}}
_lc{{_id}}_bs, _lc{{_id}}_sl, _ = {{input}}.shape
_lc{{_id}}_h = np.zeros((_lc{{_id}}_bs, _lc{{_id}}_hd), dtype=np.float32)
_lc{{_id}}_outs = []
for _lc{{_id}}_t in range(_lc{{_id}}_sl):
    _lc{{_id}}_xt = {{input}}[:, _lc{{_id}}_t, :]
    # Compute input-dependent time constant
    _lc{{_id}}_cat = np.concatenate([_lc{{_id}}_xt, _lc{{_id}}_h], axis=-1)
    _lc{{_id}}_tau = 1.0 / (1.0 + np.exp(-(np.matmul(_lc{{_id}}_cat, _lc{{_id}}_w_tau.T) + _lc{{_id}}_b_tau)))
    _lc{{_id}}_tau = _lc{{_id}}_tau * 2.0 + 0.1  # scale to (0.1, 2.1)
    # ODE integration (Euler sub-steps)
    for _lc{{_id}}_s in range(_lc{{_id}}_steps):
        _lc{{_id}}_f = np.tanh(np.matmul(_lc{{_id}}_xt, _lc{{_id}}_wih.T) + np.matmul(_lc{{_id}}_h, _lc{{_id}}_whh.T) + _lc{{_id}}_b)
        _lc{{_id}}_sens = 1.0 / (1.0 + np.exp(-np.matmul(_lc{{_id}}_h, _lc{{_id}}_w_A.T)))
        _lc{{_id}}_dh = (-_lc{{_id}}_h / _lc{{_id}}_tau) + _lc{{_id}}_f * _lc{{_id}}_sens
        _lc{{_id}}_h = _lc{{_id}}_h + _lc{{_id}}_dt * _lc{{_id}}_dh
    _lc{{_id}}_outs.append(_lc{{_id}}_h)
{{output}} = np.stack(_lc{{_id}}_outs, axis=1)
